        HOW_MAY_I_BE_OF_SERVICE_TODAY                                           = 11198,  -- How may I be of service today?
        WHAT_TO_DO_NOTHING_VIEW_LIST_OF_STORABLE                                = 11199,  -- What to do... Nothing. View list of storable armor sets. Have stored armor returned.
