        AM_I_YOU_SEEM_QUITE_FLUSTERED                                           = 11371,  -- Am I...? You seem quite flustered.
        W_W_WHY_WOULD_I_LIE_ABOUT_SOMETHING                                     = 11372,  -- W-w-why would I lie about something like that!?
        AMAZING_IT_DOESN_T_HURT_ANYMORE_YOU_VE                                  = 11373,  -- Amazing... It doesn't hurt anymore. You've become quite a fine physician, Chemioue.
        DO_YOU_REALLY_BELIEVE_SO                                                = 11374,  -- Do you really believe so?
