        IN_DYNAMIS_IT_IS_POSSIBLE_TO_COOPERATE_WITH                             = 12036,  -- In Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia], it is possible to cooperate with other characters to defeat enemies without being in the same party or alliance.
        ALSO_ITEMS_DROPPED_BY_ENEMIES_BECOME_AVAILABLE_FOR                      = 12037,  -- Also, items dropped by enemies become available for every character in the area to cast lots on. As in normal parties, the item is gained by the character who casts the highest lot.
        PLEASE_BE_AWARE_THAT_ITEMS_NOT_LOTTED_FOR                               = 12038,  -- Please be aware that items not lotted for within the restricted time may go to random characters or be lost entirely.
        STARTING_FROM_WHEN_THE_FIRST_CHARACTER_ENTERS_IF                        = 12039,  -- Starting from when the first character enters, if the number of people in Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia] reaches and remains at zero for approximately # [minute/minutes] (Earth time), the time and area designation on the % will be canceled.
        WHEN_BATTLING_ENEMIES_IN_DYNAMIS_IT_WILL_ONLY                           = 12040,  -- When battling enemies in Dynamis - [Dummy/San d'Oria/Bastok/Windurst/Jeuno/Beaucedine/Xarcabard/Valkurm/Buburimu/Qufim/Tavnazia], it will only be possible to cooperate with characters in the same party or alliance.
