        YOU_WISH_TO_IMPROVE_YOUR_TECHNIQUE_IS_THIS                              = 12097,  -- You wish to improve your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique. Is this correct?
        IT_WOULD_SEEM_YOUR_TECHNIQUE_ALREADY_EXCEEDS_MY                         = 12098,  -- It would seem your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique already exceeds my own. There is no more I can teach you.
        TRAIN_IN_THIS_TECHNIQUE_YES_NO                                          = 12099,  -- Train in this technique? Yes. No.
        VERY_WELL_NOW_LISTEN_UP_WATCH_CLOSELY_AND                               = 12100,  -- Very well! Now listen up, watch closely, and try to follow along...
        SEE_YOU_TAKE_THIS_PART_HERE_AND_YES                                     = 12101,  -- ...See, you take this part here, and... Yes, yes...just like that...
        NOW_STEADY_HERE_OR_YOU_LL_BE_PICKING                                    = 12102,  -- ...Now steady here, or you'll be picking exploded furnace shrapnel out of your face for a week! Phew, that was a close one...
        AND_BY_APPLYING_COROLLARY_FIVE_OF_HILDOLF_S                             = 12103,  -- ...And by applying Corollary Five of Hildolf's Third Theory of Inverse Transfocal Equilibrium, we find that...
        CLINK_CLANK_CLUNK_ER_LET_S_TRY_THAT                                     = 12104,  -- <Clink, clank...clunk> ...Er, let's try that once more...
        SUPERB_A_QUICK_LEARNER_I_SEE_IF_ONLY                                    = 12105,  -- ...Superb! A quick learner, I see. If only all my students were as attentive as you!
        YOUR_TECHNIQUE_INCREASES_TO_LEVEL                                       = 12106,  -- Your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique increases to level #!
        RESEARCH_INTO_THE_COMPOSITION_OF_THE_CINDER_PRODUCED                    = 12107,  -- Research into the composition of the cinder produced as a side effect of synergy just might lead to the next breakthrough in our field. Provide us with samples for analysis, and we will gladly reward your contributions.
