        GREETINGS_AND_WELL_MET_I_AM_A_VOIDWATCH                                 = 12292,  -- Greetings and well met. I am a Voidwatch scientist charged with researching the potential uses of atmacite.
        THOSE_WHO_POSSESS_MAY_COME_TO_ME_TO                                     = 12293,  -- Those who possess % may come to me to have their hard-won atmacite infused. Stratum abyssite also falls within my domain, so present to me any whose properties you wish to have analyzed.
        AH_I_M_ALSO_AUTHORIZED_TO_TELEPORT_FOLK                                 = 12294,  -- Ah, I'm also authorized to teleport folk to operation sites. Quite versatile, aren't I?
        I_BEG_OF_YOU_FRIEND_LEND_US_YOUR                                        = 12295,  -- I beg of you, friend. Lend us your stout sword arm in the fight to protect Vana'diel from the Voidwalker threat.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_HAVE                                   = 12296,  -- What will you do? Nothing for now. Have stratum abyssite examined. Request teleportation. Analyze atmacite. Ask about atmacite. Ask about atmacite enrichment.
