        THAT_DIMINUTIVE_GIRL_WAS_PRISHE_CORRECT_PERHAPS_ALL                     = 13135,  -- That diminutive girl was Prishe, correct? Perhaps all the rumors were all simply...rumors.
        WELL_YOU_HAVE_MY_THANKS_FOR_A_JOB                                       = 13136,  -- Well, you have my thanks for a job well done. I highly doubt you'll be receiving any accolades from the uncouth citizens of this cesspool, but I shall make sure word of your tremendous deeds reaches Jeuno.
        IF_YOU_LL_PERMIT_ME_TO_SPREAD_SOME                                      = 13137,  -- If you'll permit me to spread some titillating gossip, I do believe that Prishe girl was shouting something along the lines of "Bibiki Bay or bust!" before making a rather exuberant departure.
        SUPPOSEDLY_THIS_PRISHE_GIRL_HAS_LEFT_THE_SAFEHOLD                       = 13138,  -- Supposedly, this Prishe girl has left the Safehold for Bibiki Bay.
        I_WOULD_ENJOY_HEARING_HOW_SHE_PLANS_TO                                  = 13139,  -- I would enjoy hearing how she plans to travel all the way to Mindartia, however. Since Bibiki Bay lies on that continent, such sorcery should be nigh impossible!
        THE_SAME_WAY_YOU_DID_YOU_SAY_THROUGH                                    = 13140,  -- The same way you did, you say? Through a chaotically churning portal of such despairing darkness that--
